def compress_string(s: str) -> str:
    if not s:
        return ""

    compressed_parts = []

    current_char = s[0]
    current_count = 0

    for char in s:
        if char == current_char:
            current_count += 1
        else:
            compressed_parts.append(current_char)
            compressed_parts.append(str(current_count))
            current_char = char
            current_count = 1

    # Append the last character group
    compressed_parts.append(current_char)
    compressed_parts.append(str(current_count))

    compressed_s = "".join(compressed_parts)

    if len(compressed_s) < len(s):
        return compressed_s
    else:
        return s
